/// Gateway approval payload shared by stream notifications, tool-call cards,
/// and durable approval-request messages.
class NavivoxGatewayApprovalNotice {
  const NavivoxGatewayApprovalNotice({
    required this.id,
    required this.toolCallId,
    required this.prompt,
    required this.risk,
  });

  final String id;
  final String toolCallId;
  final String prompt;
  final String? risk;

  NavivoxApprovalRequest toChannelRequest() {
    return NavivoxApprovalRequest(
      id: id,
      toolCallId: toolCallId,
      prompt: prompt,
      risk: risk,
    );
  }
}

NavivoxGatewayApprovalNotice navivoxGatewayApprovalNotice({
  required NavivoxGatewayEvent event,
  required String Function() fallbackApprovalId,
}) {
  return NavivoxGatewayApprovalNotice(
    id: event.approvalId ?? fallbackApprovalId(),
    toolCallId: event.toolCallId ?? '',
    prompt: event.message ?? 'Approval required',
    risk: event.risk,
  );
}

/// Builds safety and approval messages from gateway events.
///
/// Warning events and approval events share the same scoped safety-notice
/// payload contract. Keeping that mapping together prevents those event types
/// from drifting into plain text messages or losing run/profile scope.
NavivoxChatMessage navivoxGatewaySafetyWarningMessage({
  required NavivoxGatewayEvent event,
  required String id,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
}) {
  return NavivoxChatMessage(
    id: id,
    author: NavivoxMessageAuthor.system,
    kind: NavivoxMessageKind.safetyWarning,
    createdAt: createdAt,
    safetyNotice: NavivoxSafetyNotice(
      id: id,
      severity: event.severity ?? 'warning',
      message: event.message ?? 'Safety warning',
      risk: event.risk,
    ),
    runRecordReference: event.runRecordReference,
    serverId: scope.serverId,
    profileId: scope.profileId,
  );
}

NavivoxToolApproval navivoxGatewayToolApproval({
  required NavivoxGatewayApprovalNotice notice,
}) {
  return NavivoxToolApproval(
    id: notice.id,
    status: 'approval_required',
    prompt: notice.prompt,
    risk: notice.risk,
  );
}

NavivoxChatMessage navivoxGatewayApprovalRequestMessage({
  required NavivoxGatewayEvent event,
  required NavivoxGatewayApprovalNotice notice,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
}) {
  return NavivoxChatMessage(
    id: notice.id,
    author: NavivoxMessageAuthor.system,
    kind: NavivoxMessageKind.approvalRequest,
    createdAt: createdAt,
    safetyNotice: NavivoxSafetyNotice(
      id: notice.id,
      approvalId: notice.id,
      toolCallId: notice.toolCallId,
      message: notice.prompt,
      risk: notice.risk,
    ),
    runRecordReference: event.runRecordReference,
    serverId: scope.serverId,
    profileId: scope.profileId,
  );
}

import '../../gateway/navivox_gateway_protocol.dart';
import '../../protocol/navivox_event.dart';
import '../contracts/navivox_message_scope.dart';
import 'gateway_safety_notice_policy.dart';
import 'gateway_tool_artifact_codec.dart';

/// Builds durable tool-call cards from gateway events.
///
/// Progress updates and approval-required events both mutate the same tool-call
/// card. Centralizing that merge contract keeps status, approval, artifacts,
/// run-record references, and profile scope aligned.
NavivoxChatMessage navivoxGatewayToolCallMessage({
  required String id,
  required NavivoxGatewayEvent event,
  required String status,
  required NavivoxChatMessage? priorMessage,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
}) {
  final prior = priorMessage?.toolCall;
  final messageScope = navivoxMessageScopeWithFallback(
    serverId: priorMessage?.serverId,
    profileId: priorMessage?.profileId,
    fallback: scope,
  );
  return NavivoxChatMessage(
    id: id,
    author: NavivoxMessageAuthor.assistant,
    kind: NavivoxMessageKind.toolCall,
    createdAt: priorMessage?.createdAt ?? createdAt,
    toolCall: NavivoxToolCall(
      name: event.toolName ?? prior?.name ?? 'tool',
      status: status,
      summary: navivoxBoundedGatewayToolText(
        event.message ?? event.text ?? prior?.summary ?? '',
      ),
      approval: prior?.approval,
      artifacts: navivoxGatewayToolArtifacts(
        metadata: event.metadata,
        toolCallId: id,
        prior: prior?.artifacts ?? const [],
      ),
    ),
    runRecordReference:
        event.runRecordReference ?? priorMessage?.runRecordReference,
    serverId: messageScope.serverId,
    profileId: messageScope.profileId,
  );
}

NavivoxChatMessage? navivoxGatewayToolApprovalMessage({
  required String id,
  required NavivoxGatewayEvent event,
  required NavivoxChatMessage? priorMessage,
  required NavivoxGatewayApprovalNotice notice,
  required DateTime createdAt,
  required NavivoxMessageScope scope,
}) {
  final priorTool = priorMessage?.toolCall;
  if (priorTool == null) return null;
  final messageScope = navivoxMessageScopeWithFallback(
    serverId: priorMessage?.serverId,
    profileId: priorMessage?.profileId,
    fallback: scope,
  );
  return NavivoxChatMessage(
    id: id,
    author: NavivoxMessageAuthor.assistant,
    kind: NavivoxMessageKind.toolCall,
    createdAt: priorMessage?.createdAt ?? createdAt,
    toolCall: priorTool.copyWith(
      approval: navivoxGatewayToolApproval(notice: notice),
    ),
    runRecordReference:
        event.runRecordReference ?? priorMessage?.runRecordReference,
    serverId: messageScope.serverId,
    profileId: messageScope.profileId,
  );
}

List<NavivoxToolArtifact> navivoxGatewayToolArtifacts({
  required Map<String, Object?> metadata,
  required String toolCallId,
  required List<NavivoxToolArtifact> prior,
}) {
  final parsed = navivoxToolArtifactsFromGatewayMetadata(
    metadata,
    toolCallId: toolCallId,
  );
  if (parsed.isEmpty) return prior;
  final byId = {for (final artifact in prior) artifact.id: artifact};
  for (final artifact in parsed) {
    byId[artifact.id] = artifact;
  }
  return byId.values.toList(growable: false);
}

